const compliance = $('Fetch Compliance Status').first().json;
const gaps = $('Fetch Compliance Gaps').first().json;
const coverage = $('Fetch Framework Coverage').first().json;

const weekStart = new Date();
weekStart.setDate(weekStart.getDate() - 7);
const weekLabel = `${weekStart.toISOString().split('T')[0]} to ${new Date().toISOString().split('T')[0]}`;

// Extract framework scores
const frameworks = compliance.frameworks || compliance.results || {};
const frameworkRows = Object.entries(frameworks)
  .map(([name, data]) => {
    const score = typeof data === 'object' ? (data.score || data.compliance_pct || 'N/A') : data;
    const status = score >= 80 ? 'PASS' : score >= 60 ? 'WARN' : 'FAIL';
    return `| ${name.toUpperCase()} | ${score}% | ${status} |`;
  }).join('\n') || '| No framework data available | — | — |';

// Gap summary
const totalGaps = gaps.total_gaps || gaps.count || 'N/A';
const criticalGaps = gaps.critical_gaps || gaps.critical || 'N/A';
const highGaps = gaps.high_gaps || gaps.high || 'N/A';

// Coverage
const overallCoverage = coverage.overall_coverage || coverage.pct || 'N/A';

const subject = `[ALDECI] Weekly Compliance Summary — ${weekLabel}`;
const body = `
# ALDECI Weekly Compliance Summary
**Period:** ${weekLabel}
**Generated:** ${new Date().toISOString()}

## Framework Compliance Scores
| Framework | Score | Status |
|-----------|-------|--------|
${frameworkRows}

## Compliance Gaps
| Category | Count |
|----------|-------|
| Total Open Gaps | ${totalGaps} |
| Critical Gaps | ${criticalGaps} |
| High Priority Gaps | ${highGaps} |

## Overall Control Coverage
**Coverage:** ${overallCoverage}%

## Action Items for This Week
1. Review and remediate all CRITICAL compliance gaps
2. Update evidence for controls approaching audit deadlines
3. Schedule remediation tasks for HIGH priority gaps

## Links
- Compliance Dashboard: http://localhost:5173/compliance
- Gap Analysis: http://localhost:5173/gap-analysis
- Compliance Mapping: http://localhost:5173/compliance-mapping
- Compliance Calendar: http://localhost:5173/compliance-calendar

---
*ALDECI Beast Mode — Automated Weekly Report*
`;

const slackPayload = {
  text: `📊 *Weekly Compliance Summary* — ${weekLabel}`,
  blocks: [
    {
      type: 'header',
      text: { type: 'plain_text', text: '📊 Weekly Compliance Summary' }
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Period:* ${weekLabel}\n*Total Gaps:* ${totalGaps} | *Critical:* ${criticalGaps} | *Control Coverage:* ${overallCoverage}%`
      }
    },
    {
      type: 'actions',
      elements: [
        {
          type: 'button',
          text: { type: 'plain_text', text: 'View Compliance Dashboard' },
          url: 'http://localhost:5173/compliance'
        },
        {
          type: 'button',
          text: { type: 'plain_text', text: 'View Gap Analysis' },
          url: 'http://localhost:5173/gap-analysis'
        }
      ]
    }
  ]
};

return [{ json: { subject, body, slackPayload, weekLabel } }];
